import { CreditCardOutlined, QrcodeOutlined, } from '@ant-design/icons';
import { Tabs } from 'antd';
import { useState } from 'react';
import CustomModal from 'src/components/Modal/CustomModal';
import ElectronicPayment from './paymentMethod/ElectronicPayment ';
import QRCodePayment from './paymentMethod/QRCodePayment ';
import PropTypes from "prop-types";

const { TabPane } = Tabs;

const PaymentMethodModal = ({ open, onClose, amount }) => {
  const [activeTab, setActiveTab] = useState('qr');

  const handleTabChange = (key) => {
    setActiveTab(key);
  };

  return (
    <CustomModal
      open={open}
      onCancel={onClose}
      footer={null}
      width={1000}
      centered
    >
      <Tabs activeKey={activeTab} onChange={handleTabChange}>
        <TabPane
          tab={
            <span>
              <QrcodeOutlined /> Mã QR
            </span>
          }
          key="qr"
        >
          <QRCodePayment amount={amount} />
        </TabPane>
        <TabPane
          tab={
            <span>
              <CreditCardOutlined /> Cổng thanh toán điện tử
            </span>
          }
          key="electronic"
        >
          <ElectronicPayment amount={amount} />
        </TabPane>
      </Tabs>
    </CustomModal>
  );
};

PaymentMethodModal.propTypes = {
  open: PropTypes.bool.isRequired,
  onClose: PropTypes.func.isRequired,
  amount: PropTypes.number.isRequired,
};


export default PaymentMethodModal;
