import {
  AlertOutlined,
  CalendarOutlined,
  DollarOutlined,
} from "@ant-design/icons"
import {
  Badge,
  Card,
  Checkbox,
  Collapse,
  Empty,
  Skeleton,
  Space,
  Typography,
  Row,
  Col,
} from "antd"
import dayjs from "dayjs"
import { useEffect, useMemo, useState } from "react"
import AssociationService from "src/services/AssociationService"
import FeeManagement from "src/services/FeeManagement"
import PaymentMethodModal from "./PaymentMethod"
import ButtonCustom from "src/components/MyButton/Button"
import "../styles/UnpaidListTable.scss"

const { Text } = Typography
const { Panel } = Collapse

function UnpaidFeesList() {
  const [listAssociation, setListAssociation] = useState([])
  const [loading, setLoading] = useState(false)
  const [dataByAssociation, setDataByAssociation] = useState({})
  const [selectedKeys, setSelectedKeys] = useState([])
  const [openModal, setOpenModal] = useState(false)

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true)
      try {
        const res = await AssociationService.getMyAssociationList()
        const list = res?.Object || []
        setListAssociation(list)

        const allFees = {}
        await Promise.all(
          list.map(async (assoc) => {
            const result = await FeeManagement.getMyFeeAssignment({
              AssociationId: assoc.AssociationID,
              PaymentStatus: 1,
            })
            allFees[assoc.AssociationID] =
              result?.Object?.map((i) => ({
                ...i,
                key: i.FeeAssignmentID,
              })) || []
          })
        )
        setDataByAssociation(allFees)
      } catch (err) {
        console.error("Error:", err)
      } finally {
        setLoading(false)
      }
    }
    fetchData()
  }, [])

  const isOverdue = (dueDate) => dayjs(dueDate).isBefore(dayjs(), "day")

  const toggleSelect = (id) => {
    setSelectedKeys((prev) =>
      prev.includes(id) ? prev.filter((k) => k !== id) : [...prev, id]
    )
  }

  const allFeeKeys = useMemo(
    () =>
      Object.values(dataByAssociation)
        .flat()
        .map((fee) => fee.FeeAssignmentID),
    [dataByAssociation]
  )

  const totalSelectedAmount = useMemo(() => {
    let sum = 0
    Object.values(dataByAssociation).forEach((fees) => {
      fees.forEach((fee) => {
        if (selectedKeys.includes(fee.FeeAssignmentID)) {
          sum += Number(fee.Amount)
        }
      })
    })
    return sum
  }, [selectedKeys, dataByAssociation])

  const hasUnpaidFees = Object.values(dataByAssociation).some(
    (fees) => fees.length > 0
  )

  const totalUnpaidCount = Object.values(dataByAssociation).reduce(
    (acc, fees) => acc + fees.length,
    0
  )

  if (loading)
    return (
      <div style={{ padding: 24 }}>
        <Skeleton active paragraph={{ rows: 5 }} />
      </div>
    )

  if (!hasUnpaidFees)
    return (
      <Empty
        description="Không có khoản phí chưa đóng"
        imageStyle={{ height: 120 }}
      />
    )

  return (
    <div style={{ margin: "0 auto" }}>
      <div className="unpaid-list-notify" style={{ marginBottom: 24 }}>
        <AlertOutlined style={{ color: "#fa8c16", marginRight: 8 }} />
        <Text strong>
          Bạn có{" "}
          <span style={{ color: "#fa8c16" }}>{totalUnpaidCount}</span> khoản phí
          chưa đóng
        </Text>
      </div>

      <Collapse accordion defaultActiveKey={listAssociation[0]?.AssociationID}>
        {listAssociation.map((assoc) => {
          const fees = dataByAssociation[assoc.AssociationID] || []
          if (fees.length === 0) return null

          return (
            <Panel
              key={assoc.AssociationID}
              header={
                <span>
                  <Checkbox
                    style={{ marginRight: 8 }}
                    checked={fees.every((f) =>
                      selectedKeys.includes(f.FeeAssignmentID)
                    )}
                    indeterminate={
                      fees.some((f) =>
                        selectedKeys.includes(f.FeeAssignmentID)
                      ) &&
                      !fees.every((f) =>
                        selectedKeys.includes(f.FeeAssignmentID)
                      )
                    }
                    onClick={(e) => e.stopPropagation()}
                    onChange={(e) => {
                      const checked = e.target.checked
                      const ids = fees.map((f) => f.FeeAssignmentID)
                      setSelectedKeys((prev) =>
                        checked
                          ? [...new Set([...prev, ...ids])]
                          : prev.filter((k) => !ids.includes(k))
                      )
                    }}
                  />
                  <Text strong style={{ color: "#1d39c4" }}>
                    {assoc.AssociationName}
                  </Text>
                </span>
              }
            >
              <Space direction="vertical" style={{ width: "100%" }}>
                {fees.map((fee) => (
                  <Card
                    key={fee.FeeAssignmentID}
                    className="fee-card"
                    style={{
                      borderRadius: 8,
                      background: selectedKeys.includes(fee.FeeAssignmentID)
                        ? "#e6f7ff"
                        : "#fff",
                    }}
                  >
                    <Row align="middle" gutter={16}>
                      <Col>
                        <Checkbox
                          checked={selectedKeys.includes(fee.FeeAssignmentID)}
                          onChange={() => toggleSelect(fee.FeeAssignmentID)}
                        />
                      </Col>
                      <Col flex="auto">
                        <Text strong>{fee.Note || "Không có nội dung"}</Text>
                        <div style={{ marginTop: 4 }}>
                          <CalendarOutlined style={{ marginRight: 4 }} />
                          <Text type="secondary">
                            Hạn: {dayjs(fee.DueDate).format("DD/MM/YYYY")}
                          </Text>
                          {isOverdue(fee.DueDate) && (
                            <Badge
                              count="Quá hạn"
                              style={{
                                marginLeft: 12,
                                backgroundColor: "#ff4d4f",
                              }}
                            />
                          )}
                        </div>
                      </Col>
                      <Col>
                        <DollarOutlined
                          style={{ color: "#52c41a", marginRight: 4 }}
                        />
                        <Text strong style={{ color: "#52c41a" }}>
                          {Number(fee.Amount).toLocaleString()}₫
                        </Text>
                      </Col>
                    </Row>
                  </Card>
                ))}
              </Space>
            </Panel>
          )
        })}
      </Collapse>

      <div
        className="unpaid-sticky-footer"
        style={{
          background: "#fff",
          padding: "16px 24px",
          boxShadow: "0 -2px 8px rgba(0, 0, 0, 0.1)",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
        }}
      >
        <Checkbox
          indeterminate={
            selectedKeys.length > 0 &&
            selectedKeys.length < allFeeKeys.length
          }
          checked={
            selectedKeys.length === allFeeKeys.length &&
            allFeeKeys.length > 0
          }
          onChange={(e) =>
            setSelectedKeys(e.target.checked ? allFeeKeys : [])
          }
        >
          Chọn tất cả ({allFeeKeys.length})
        </Checkbox>
        <Space>
          <Text strong style={{ fontSize: 18, color: "#1d39c4" }}>
            Tổng: {totalSelectedAmount.toLocaleString()}₫
          </Text>
          <ButtonCustom
            size="large"
            onClick={() => setOpenModal(true)}
            disabled={selectedKeys.length === 0}
          >
            Thanh toán
          </ButtonCustom>
        </Space>
      </div>

      <PaymentMethodModal
        open={openModal}
        onClose={() => setOpenModal(false)}
        amount={totalSelectedAmount}
      />
    </div>
  )
}

export default UnpaidFeesList
